qry:select.qry:xquery:
				for $r in SQL('

SELECT
PRY04_TRABAJOS.e_duracion,
PRY03_UND_TIEMPO.e_minutos

FROM
PRY04_TRABAJOS,
PRY03_UND_TIEMPO

JOIN
PRY04_TRABAJOS.oi_unidad_tiempo INNER PRY03_UND_TIEMPO.oi_unidad_tiempo

WHERE
PRY04_TRABAJOS.oi_perfil = {$PARAM/@oi_perfil} 
{%? ($FILTER/@f_desde!='')
   	{% AND PRY04_TRABAJOS.f_fecha >= {$FILTER/@f_desde} %}
   	{%%} 
%}
{%? ($FILTER/@f_hasta!='')
   	{% AND PRY04_TRABAJOS.f_fecha <= {$FILTER/@f_hasta} %}
   	{%%} 
%}

')/ROWS/ROW
